# Category: path_traversal

import java.io.File
import java.nio.file.Path
import java.nio.file.Paths
import play.api.mvc._

class FileController extends Controller {
  def serveFile(filename: String) = Action { implicit request =>
    val baseDir = Paths.get("uploads")
    val path = Paths.get(baseDir.toString, filename)
      .normalize()
      .toAbsolutePath()

    if (path.isAbsolute || path.startsWith(baseDir)) {
      val file = new File(path.toFile.toString)
      if (file.exists()) {
        val source = scala.io.Source.fromFile(file.getAbsolutePath)
        Ok(source.mkString).withHeaders(
          CONTENT_DISPOSITION -> s"attachment; filename=$filename"
        )
      } else {
        NotFound
      }
    } else {
      Forbidden
    }
  }
}